      "@tanstack/react-form",
      "class-variance-authority",
      "clsx",
      "jotai",
      "next/cache",
      "next/headers",
      "next/link",
      "next/navigation",
      "tailwind-merge",
      "valibot",
    ],
  },
  test: {
    name: "client",
    include: [
      "**/*.client.test.ts",
      "**/*.client.test.tsx",
    ],
    // lib/test/** はテスト用ユーティリティのため、テストファイルは置かない
    exclude: ["**/node_modules/**", "lib/test/**"],
    browser: {
      enabled: true,
      provider: playwright(),
      headless: true,
      instances: [{ browser: "chromium" }],
    },
  },
});

